-- ============================================
-- Migration 002: Full FCI breed seed (359 breeds)
-- Adds fci_id, fci_url, photo_credit and enriched columns,
-- then upserts all 359 FCI breeds from razze-enriched.json
-- Sources: FCI, Italian Wikipedia, dogapi.dog, AKC, Wikimedia Commons
-- ============================================

ALTER TABLE breeds ADD COLUMN IF NOT EXISTS fci_id INTEGER;
ALTER TABLE breeds ADD COLUMN IF NOT EXISTS fci_url TEXT;
ALTER TABLE breeds ADD COLUMN IF NOT EXISTS photo_credit TEXT;
ALTER TABLE breeds ADD COLUMN IF NOT EXISTS weight_min_kg INTEGER;
ALTER TABLE breeds ADD COLUMN IF NOT EXISTS weight_max_kg INTEGER;
ALTER TABLE breeds ADD COLUMN IF NOT EXISTS lifespan_min INTEGER;
ALTER TABLE breeds ADD COLUMN IF NOT EXISTS lifespan_max INTEGER;
ALTER TABLE breeds ADD COLUMN IF NOT EXISTS hypoallergenic BOOLEAN;
ALTER TABLE breeds ADD COLUMN IF NOT EXISTS quiz_attributes JSONB;
ALTER TABLE breeds ADD COLUMN IF NOT EXISTS wikipedia_url_it TEXT;

CREATE INDEX IF NOT EXISTS idx_breeds_fci_id ON breeds(fci_id);
CREATE INDEX IF NOT EXISTS idx_breeds_group ON breeds(group_fci);

INSERT INTO breeds (
  name_it, name_en, slug, group_fci, group_name_it, description_it, image_url,
  origin_country, size_category, is_italian_breed, is_popular,
  fci_id, fci_url, photo_credit, weight_min_kg, weight_max_kg,
  lifespan_min, lifespan_max, hypoallergenic, quiz_attributes, wikipedia_url_it
) VALUES
  ('Pointer Inglese', 'ENGLISH POINTER', 'pointer-inglese', 7, 'Cani da ferma', 'Il pointer è una razza canina di origine britannica che prende il nome dalla sua capacità di puntare la preda.', 'https://upload.wikimedia.org/wikipedia/commons/thumb/c/c5/English_pointer.jpg/330px-English_pointer.jpg', 'Regno Unito', 'grande', false, false, 1, 'https://www.fci.be/en/nomenclature/ENGLISH-POINTER-1.html', 'Wikimedia Commons (CC BY-SA)', 20, 30, 12, 14, false, NULL, 'https://it.wikipedia.org/wiki/Pointer_inglese'),
  ('Setter Inglese', 'ENGLISH SETTER', 'setter-inglese', 7, 'Cani da ferma', 'Il setter inglese è una razza canina originaria dell''Inghilterra, affinata intorno al 1838 da sir Edward Laverack (1798-1877) dopo un''accurata selezione a partire da vari ceppi genetici preesistenti in terra d''albione. In seguito la razza venne conservata e ne venne promossa la diffusione ad opera di sir Purcell Llewellin e di William Humphrey. È un cane molto dolce e mite, adatto alla compagnia ed eccellente per la caccia. Infatti, il nome stesso deriva dal verbo inglese to set, cioè puntare o guardare fissamente.', 'https://upload.wikimedia.org/wikipedia/commons/thumb/7/71/English_setter.jpg/330px-English_setter.jpg', 'Regno Unito', 'grande', false, false, 2, 'https://www.fci.be/en/nomenclature/ENGLISH-SETTER-2.html', 'Wikimedia Commons (CC BY-SA)', 20, 30, 12, 14, false, '{"energy": null, "trainability": null, "shedding": 5, "barking": 3, "good_with_children": 3, "good_with_other_dogs": 3}'::jsonb, 'https://it.wikipedia.org/wiki/English_Setter'),
  ('Kerry Blue Terrier', 'KERRY BLUE TERRIER', 'kerry-blue-terrier', 3, 'Terrier', 'Il Kerry Blue Terrier è una razza canina irlandese riconosciuta dalla FCI che, contrariamente all''apparenza non ha le sue origini nella regione omonima bensì da Tipperary. Nel paese d''origine è infatti chiamato Irish Blue Terrier.', 'https://upload.wikimedia.org/wikipedia/commons/thumb/f/f4/Kerry_Blue_Terrier.jpg/330px-Kerry_Blue_Terrier.jpg', 'Irlanda', 'media', false, false, 3, 'https://www.fci.be/en/nomenclature/KERRY-BLUE-TERRIER-3.html', 'Wikimedia Commons (CC BY-SA)', 13, 17, 12, 14, true, '{"energy": null, "trainability": null, "shedding": 1, "barking": 5, "good_with_children": 3, "good_with_other_dogs": 3}'::jsonb, 'https://it.wikipedia.org/wiki/Kerry_blue_terrier'),
  ('Cairn Terrier', 'CAIRN TERRIER', 'cairn-terrier', 3, 'Terrier', 'Il Cairn Terrier è una razza canina di origine scozzese riconosciuta dalla FCI.', 'https://upload.wikimedia.org/wikipedia/commons/thumb/d/de/Cairn-Terrier.jpg/330px-Cairn-Terrier.jpg', 'Regno Unito', 'media', false, false, 4, 'https://www.fci.be/en/nomenclature/CAIRN-TERRIER-4.html', 'Wikimedia Commons (CC BY-SA)', 5, 6, 14, 16, false, '{"energy": null, "trainability": null, "shedding": 2, "barking": 5, "good_with_children": 3, "good_with_other_dogs": 3}'::jsonb, 'https://it.wikipedia.org/wiki/Cairn_terrier'),
  ('Cocker Spaniel Inglese', 'ENGLISH COCKER SPANIEL', 'cocker-spaniel-inglese', 8, 'Cani da riporto', 'Il cocker spaniel inglese è una razza di cane da caccia e da tartufo particolarmente elegante ed aristocratica. Originariamente fu selezionata per la caccia della beccaccia, ma attualmente per le sue caratteristiche è una delle migliori per quasi tutti i tipi di caccia. Ottimo cane nuotatore, è adatto al lavoro anche in zone paludose e quelle in cui la vegetazione è fitta. Ha un carattere allegro e la coda dal movimento incessante e gioioso, in particolare quando segue una traccia, incurante delle difficoltà del terreno. Ama correre e giocare con il padrone, è forte, sportivo, molto armonioso e compatto.', 'https://upload.wikimedia.org/wikipedia/commons/thumb/7/70/EnglishCockerSpaniel_simon.jpg/330px-EnglishCockerSpaniel_simon.jpg', 'Regno Unito', 'media', false, false, 5, 'https://www.fci.be/en/nomenclature/ENGLISH-COCKER-SPANIEL-5.html', 'Wikimedia Commons (CC BY-SA)', 14, 16, 12, 14, false, '{"energy": null, "trainability": null, "shedding": 2, "barking": 3, "good_with_children": 5, "good_with_other_dogs": 5}'::jsonb, 'https://it.wikipedia.org/wiki/Cocker_spaniel_inglese'),
  ('Setter Gordon', 'GORDON SETTER', 'setter-gordon', 7, 'Cani da ferma', 'Il setter scozzese o setter gordon, o anche, black and tans setter è un cane da ferma britannico di media taglia, originario della Scozia.', 'https://upload.wikimedia.org/wikipedia/commons/thumb/c/c0/Orrvilas_enska_w800px.jpg/330px-Orrvilas_enska_w800px.jpg', 'Regno Unito', 'grande', false, false, 6, 'https://www.fci.be/en/nomenclature/GORDON-SETTER-6.html', 'Wikimedia Commons (CC BY-SA)', 25, 32, 12, 14, false, '{"energy": null, "trainability": null, "shedding": 3, "barking": 3, "good_with_children": 3, "good_with_other_dogs": 3}'::jsonb, 'https://it.wikipedia.org/wiki/Gordon_setter'),
  ('Airedale Terrier', 'AIREDALE TERRIER', 'airedale-terrier', 3, 'Terrier', 'L''Airedale terrier è una razza canina britannica riconosciuta dalla FCI, che deve il suo nome all''Airedale, la regione geografica dello Yorkshire che comprende la vallata del fiume Aire. Il nome significa "terrier della vallata dell''Aire".', 'https://upload.wikimedia.org/wikipedia/commons/thumb/7/7a/Airedale_terrier_744.jpg/330px-Airedale_terrier_744.jpg', 'Regno Unito', 'media', false, false, 7, 'https://www.fci.be/en/nomenclature/AIREDALE-TERRIER-7.html', 'Wikimedia Commons (CC BY-SA)', 20, 23, 12, 14, false, '{"energy": null, "trainability": null, "shedding": 2, "barking": 3, "good_with_children": 3, "good_with_other_dogs": 3}'::jsonb, 'https://it.wikipedia.org/wiki/Airedale_terrier'),
  ('Terrier Australiano', 'AUSTRALIAN TERRIER', 'terrier-australiano', 3, 'Terrier', NULL, 'https://upload.wikimedia.org/wikipedia/commons/7/7e/Australian_Silky_Terrier_Pup.jpg', 'Australia', 'media', false, false, 8, 'https://www.fci.be/en/nomenclature/AUSTRALIAN-TERRIER-8.html', 'Wikimedia Commons (CC BY-SA 3.0)', 4, 6, 14, 16, false, '{"energy": null, "trainability": null, "shedding": 1, "barking": 3, "good_with_children": 5, "good_with_other_dogs": 3}'::jsonb, NULL),
  ('Bedlington Terrier', 'BEDLINGTON TERRIER', 'bedlington-terrier', 3, 'Terrier', 'Il Bedlington Terrier è una razza canina britannica riconosciuta dalla FCI che deve il suo nome alla città mineraria di Bedlington, nel Northumberland.', 'https://upload.wikimedia.org/wikipedia/commons/thumb/f/fe/Boutchie_apres_championnat_004.JPG/330px-Boutchie_apres_championnat_004.JPG', 'Regno Unito', 'media', false, false, 9, 'https://www.fci.be/en/nomenclature/BEDLINGTON-TERRIER-9.html', 'Wikimedia Commons (CC BY-SA)', 7, 9, 12, 14, false, '{"energy": null, "trainability": null, "shedding": 1, "barking": 3, "good_with_children": 3, "good_with_other_dogs": 3}'::jsonb, 'https://it.wikipedia.org/wiki/Bedlington_terrier'),
  ('Border Terrier', 'BORDER TERRIER', 'border-terrier', 3, 'Terrier', 'Il Border Terrier è una razza canina britannica riconosciuta dalla FCI che deve il suo nome alla regione tra la Scozia e l''Inghilterra.', 'https://upload.wikimedia.org/wikipedia/commons/thumb/2/29/Border-terrier-bitch.jpg/330px-Border-terrier-bitch.jpg', 'Regno Unito', 'media', false, false, 10, 'https://www.fci.be/en/nomenclature/BORDER-TERRIER-10.html', 'Wikimedia Commons (CC BY-SA)', 6, 8, 14, 16, false, '{"energy": null, "trainability": null, "shedding": 2, "barking": 3, "good_with_children": 5, "good_with_other_dogs": 3}'::jsonb, 'https://it.wikipedia.org/wiki/Border_terrier'),
  ('Bull Terrier', 'BULL TERRIER', 'bull-terrier', 3, 'Terrier', 'Il bull terrier è una razza canina originaria della Gran Bretagna riconosciuta dalla FCI.', 'https://upload.wikimedia.org/wikipedia/commons/thumb/c/c8/Bull_Terrier_Standard_Maschio_-_Bianco.jpg/330px-Bull_Terrier_Standard_Maschio_-_Bianco.jpg', 'Regno Unito', 'media', false, false, 11, 'https://www.fci.be/en/nomenclature/BULL-TERRIER-11.html', 'Wikimedia Commons (CC BY-SA)', 18, 22, 12, 15, false, '{"energy": null, "trainability": null, "shedding": 3, "barking": 3, "good_with_children": 3, "good_with_other_dogs": 1}'::jsonb, 'https://it.wikipedia.org/wiki/Bull_terrier'),
  ('Fox Terrier a pelo liscio', 'FOX TERRIER (SMOOTH)', 'fox-terrier-a-pelo-liscio', 3, 'Terrier', 'Fox Terrier è il nome che viene dato a due distinte razze canine riconosciute inizialmente dal Kennel Club inglese. Fanno entrambe parte del terzo gruppo canino, quello dei terrier. Per quanto il nome sia il medesimo esistono due razze distinte che portano il nome fox terrier: il fox terrier a pelo liscio e il fox terrier a pelo ruvido. Nonostante questo è bene notare che la sola differenza tra le due razze e tra i due standard, che a prima vista possono apparire molto diversi, consiste nella tessitura del pelo. La varietà a pelo ruvido ha, infatti, un mantello ispido, duro e spesso, mentre quella a pelo liscio presenta un fitto mantello aderente e lucido, uniforme su tutto il corpo.', 'https://upload.wikimedia.org/wikipedia/commons/thumb/e/e3/Fox_terrier_smooth.jpg/330px-Fox_terrier_smooth.jpg', 'Regno Unito', 'media', false, false, 12, 'https://www.fci.be/en/nomenclature/FOX-TERRIER-SMOOTH-12.html', 'Wikimedia Commons (CC BY-SA)', NULL, NULL, NULL, NULL, NULL, NULL, 'https://it.wikipedia.org/wiki/Fox_terrier'),
  ('English Toy Terrier', 'ENGLISH TOY TERRIER (BLACK &TAN)', 'english-toy-terrier', 3, 'Terrier', NULL, 'https://upload.wikimedia.org/wikipedia/commons/thumb/f/f5/English_Toy_Terrier_600_01.jpg/500px-English_Toy_Terrier_600_01.jpg', 'Regno Unito', 'piccola', false, false, 13, 'https://www.fci.be/en/nomenclature/ENGLISH-TOY-TERRIER-BLACK-TAN-13.html', 'Wikimedia Commons (CC BY-SA 3.0)', NULL, NULL, NULL, NULL, NULL, NULL, NULL),
  ('Vallhund Svedese', 'SWEDISH VALLHUND', 'vallhund-svedese', 5, 'Cani di tipo Spitz e primitivo', NULL, 'https://upload.wikimedia.org/wikipedia/commons/6/68/SwedishVallhundAgility_wb.jpg', 'Svezia', 'media', false, false, 14, 'https://www.fci.be/en/nomenclature/SWEDISH-VALLHUND-14.html', 'Wikimedia Commons (CC BY-SA 3.0)', 13, 16, 12, 15, false, '{"energy": null, "trainability": null, "shedding": 3, "barking": 3, "good_with_children": 5, "good_with_other_dogs": 3}'::jsonb, NULL),
  ('Pastore Belga', 'BELGIAN SHEPHERD DOG', 'pastore-belga', 1, 'Cani da pastore e bovari', 'Il cane da pastore belga è una razza di cane da pastore che si divide in quattro varietà: Groenendael, Laekenois, Malinois e Tervueren. La loro storia, il loro carattere, le loro cure e i consigli forniti dagli allevatori sono identici; cambia lo standard di razza.', 'https://upload.wikimedia.org/wikipedia/commons/thumb/8/8d/PicardDuc.jpg/330px-PicardDuc.jpg', 'Belgio', 'grande', false, false, 15, 'https://www.fci.be/en/nomenclature/BELGIAN-SHEPHERD-DOG-15.html', 'Wikimedia Commons (CC BY-SA)', NULL, NULL, NULL, NULL, NULL, NULL, 'https://it.wikipedia.org/wiki/Cane_da_pastore_belga'),
  ('Bobtail', 'OLD ENGLISH SHEEPDOG', 'bobtail', 1, 'Cani da pastore e bovari', 'Il bobtail, o vecchio cane da pastore inglese, è una razza canina di origine britannica, riconosciuta dalla FCI.', 'https://upload.wikimedia.org/wikipedia/commons/thumb/7/7b/Bobtail.JPG/330px-Bobtail.JPG', 'Regno Unito', 'grande', false, false, 16, 'https://www.fci.be/en/nomenclature/OLD-ENGLISH-SHEEPDOG-16.html', 'Wikimedia Commons (CC BY-SA)', 40, 50, 10, 12, false, '{"energy": null, "trainability": null, "shedding": 3, "barking": 3, "good_with_children": 5, "good_with_other_dogs": 3}'::jsonb, 'https://it.wikipedia.org/wiki/Bobtail'),
  ('Griffon Nivernais', 'GRIFFON NIVERNAIS', 'griffon-nivernais', 6, 'Segugi e cani per pista di sangue', 'Il Griffon Nivernais è una razza canina di tipo segugio, originaria della Francia. È un cane da caccia versatile, utilizzato su selvaggina di piccola e grossa taglia, in muta o individualmente. La razza odierna è una ricostruzione di un''antica razza canina della regione del Nivernais.', 'https://upload.wikimedia.org/wikipedia/commons/thumb/7/75/Griffon_nivernais.jpg/330px-Griffon_nivernais.jpg', 'Francia', 'media', false, false, 17, 'https://www.fci.be/en/nomenclature/GRIFFON-NIVERNAIS-17.html', 'Wikimedia Commons (CC BY-SA)', NULL, NULL, NULL, NULL, NULL, NULL, 'https://it.wikipedia.org/wiki/Griffon_Nivernais'),
  ('Briquet Griffon Vendéen', 'BRIQUET GRIFFON VENDEEN', 'briquet-griffon-vendeen', 6, 'Segugi e cani per pista di sangue', 'Il Briquet Griffon Vendéen è una razza canina da caccia originaria della Francia. Allevato prima della prima guerra mondiale dal conte d''Elva, era quasi estinto dopo la seconda guerra mondiale, ma grazie a Hubert Dezamy, giudice francese di esposizioni canine, la razza è stata restaurata, riapparendo a Fontenay-le-Comte nel 1946. Una muta di Briquet ha vinto la coppa di Francia per prove su capriolo nel 1995, ma la razza viene usata anche per la caccia al cinghiale.', 'https://upload.wikimedia.org/wikipedia/commons/thumb/7/77/Briquet_Griffon_Vendeen.jpg/330px-Briquet_Griffon_Vendeen.jpg', 'Francia', 'media', false, false, 19, 'https://www.fci.be/en/nomenclature/BRIQUET-GRIFFON-VENDEEN-19.html', 'Wikimedia Commons (CC BY-SA)', NULL, NULL, NULL, NULL, NULL, NULL, 'https://it.wikipedia.org/wiki/Briquet_Griffon_Vend%C3%A9en'),
  ('Ariégeois', 'ARIEGEOIS', 'ariegeois', 6, 'Segugi e cani per pista di sangue', 'L''Ariégeois è una razza canina francese riconosciuta dalla FCI. È un segugio originario del dipartimento dell''Ariège il cui standard fu redatto solo nel 1912.', 'https://upload.wikimedia.org/wikipedia/commons/thumb/b/b0/Ariegeois.jpg/330px-Ariegeois.jpg', 'Francia', 'media', false, false, 20, 'https://www.fci.be/en/nomenclature/ARIEGEOIS-20.html', 'Wikimedia Commons (CC BY-SA)', NULL, NULL, NULL, NULL, NULL, NULL, 'https://it.wikipedia.org/wiki/Ari%C3%A9geois'),
  ('Gascon Saintongeois', 'GASCON SAINTONGEOIS', 'gascon-saintongeois', 6, 'Segugi e cani per pista di sangue', 'Gascon Saintongeois è una razza canina di origine francese riconosciuta dalla FCI.', 'https://upload.wikimedia.org/wikipedia/commons/thumb/9/9b/Isogascognesaintonge.jpg/330px-Isogascognesaintonge.jpg', 'Francia', 'media', false, false, 21, 'https://www.fci.be/en/nomenclature/GASCON-SAINTONGEOIS-21.html', 'Wikimedia Commons (CC BY-SA)', NULL, NULL, NULL, NULL, NULL, NULL, 'https://it.wikipedia.org/wiki/Gascon_saintongeois'),
  ('Great Gascony Blue', 'GREAT GASCONY BLUE', 'great-gascony-blue', 6, 'Segugi e cani per pista di sangue', NULL, 'https://upload.wikimedia.org/wikipedia/commons/thumb/6/62/Grand_Bleu_de_Gascogne_in_a_blue_dogcollar.jpg/500px-Grand_Bleu_de_Gascogne_in_a_blue_dogcollar.jpg', 'Francia', 'media', false, false, 22, 'https://www.fci.be/en/nomenclature/GREAT-GASCONY-BLUE-22.html', 'Wikimedia Commons (CC BY-SA 3.0)', NULL, NULL, NULL, NULL, NULL, NULL, NULL),
  ('Poitevin', 'POITEVIN', 'poitevin', 6, 'Segugi e cani per pista di sangue', 'Il Poitevin, noto anche come cane di Haut-Poitou, è un razza di segugio francese della provincia di Poitou, questo segugio fu creato nel XVII secolo per la caccia ai lupi e alla grande selvaggina. 
È una delle 29 razze dei segugi francesi; la Federazione Cinologica Internazionale lo elenca nel gruppo 6, sezione 1, standard n° 24.', 'https://upload.wikimedia.org/wikipedia/commons/thumb/9/9f/Poitevin_Hound.jpg/330px-Poitevin_Hound.jpg', 'Francia', 'media', false, false, 24, 'https://www.fci.be/en/nomenclature/POITEVIN-24.html', 'Wikimedia Commons (CC BY-SA)', NULL, NULL, NULL, NULL, NULL, NULL, 'https://it.wikipedia.org/wiki/Poitevin'),
  ('Billy', 'BILLY', 'billy', 6, 'Segugi e cani per pista di sangue', NULL, 'https://upload.wikimedia.org/wikipedia/commons/thumb/b/be/Bill_Kaulitz_2010.JPG/500px-Bill_Kaulitz_2010.JPG', 'Francia', 'media', false, false, 25, 'https://www.fci.be/en/nomenclature/BILLY-25.html', 'Wikimedia Commons (CC BY-SA 3.0)', NULL, NULL, NULL, NULL, NULL, NULL, NULL),
  ('Artois Hound', 'ARTOIS HOUND', 'artois-hound', 6, 'Segugi e cani per pista di sangue', NULL, 'https://www.fci.be/Nomenclature/Illustrations/028g06.jpg', 'Francia', 'media', false, false, 28, 'https://www.fci.be/en/nomenclature/ARTOIS-HOUND-28.html', 'FCI — Fédération Cynologique Internationale', NULL, NULL, NULL, NULL, NULL, NULL, NULL),
  ('Porcelaine', 'PORCELAINE', 'porcelaine', 6, 'Segugi e cani per pista di sangue', 'Il Porcelaine è un segugio francese di antiche origini, proveniente dalla regione della Franca Contea.', 'https://upload.wikimedia.org/wikipedia/commons/thumb/3/3e/Porcelaine_2009_pl4.jpg/330px-Porcelaine_2009_pl4.jpg', 'Francia', 'media', false, false, 30, 'https://www.fci.be/en/nomenclature/PORCELAINE-30.html', 'Wikimedia Commons (CC BY-SA)', 8, 10, 12, 15, false, '{"energy": null, "trainability": null, "shedding": null, "barking": 1, "good_with_children": 5, "good_with_other_dogs": 5}'::jsonb, 'https://it.wikipedia.org/wiki/Porcelaine'),
  ('Small Blue Gascony', 'SMALL BLUE GASCONY', 'small-blue-gascony', 6, 'Segugi e cani per pista di sangue', NULL, 'https://upload.wikimedia.org/wikipedia/commons/thumb/d/da/Small_Blue_Gascony_Hound_1.jpg/500px-Small_Blue_Gascony_Hound_1.jpg', 'Francia', 'media', false, false, 31, 'https://www.fci.be/en/nomenclature/SMALL-BLUE-GASCONY-31.html', 'Wikimedia Commons (CC BY-SA 4.0)', NULL, NULL, NULL, NULL, NULL, NULL, NULL),
  ('Blue Gascony Griffon', 'BLUE GASCONY GRIFFON', 'blue-gascony-griffon', 6, 'Segugi e cani per pista di sangue', NULL, 'https://upload.wikimedia.org/wikipedia/commons/thumb/1/15/04031124_Griffon_Bleu_de_Gascogne.jpg/500px-04031124_Griffon_Bleu_de_Gascogne.jpg', 'Francia', 'media', false, false, 32, 'https://www.fci.be/en/nomenclature/BLUE-GASCONY-GRIFFON-32.html', 'Wikimedia Commons (CC BY-SA 3.0)', NULL, NULL, NULL, NULL, NULL, NULL, NULL),
  ('Grand Basset Griffon Vendeen', 'GRAND BASSET GRIFFON VENDEEN', 'grand-basset-griffon-vendeen', 6, 'Segugi e cani per pista di sangue', NULL, 'https://upload.wikimedia.org/wikipedia/commons/thumb/7/76/G_Basset_Griffon_Vendeen_600.jpg/500px-G_Basset_Griffon_Vendeen_600.jpg', 'Francia', 'media', false, false, 33, 'https://www.fci.be/en/nomenclature/GRAND-BASSET-GRIFFON-VENDEEN-33.html', 'Wikimedia Commons (CC BY-SA 3.0)', NULL, NULL, NULL, NULL, NULL, '{"energy": null, "trainability": null, "shedding": 3, "barking": 5, "good_with_children": 3, "good_with_other_dogs": 3}'::jsonb, NULL),
  ('Norman Artesien Basset', 'NORMAN ARTESIEN BASSET', 'norman-artesien-basset', 6, 'Segugi e cani per pista di sangue', NULL, 'https://www.fci.be/Nomenclature/Illustrations/034g06.jpg', 'Francia', 'media', false, false, 34, 'https://www.fci.be/en/nomenclature/NORMAN-ARTESIEN-BASSET-34.html', 'FCI — Fédération Cynologique Internationale', NULL, NULL, NULL, NULL, NULL, NULL, NULL),
  ('Blue Gascony Basset', 'BLUE GASCONY BASSET', 'blue-gascony-basset', 6, 'Segugi e cani per pista di sangue', NULL, 'https://upload.wikimedia.org/wikipedia/commons/thumb/4/47/Basset_bleu_de_Gascogne.jpg/500px-Basset_bleu_de_Gascogne.jpg', 'Francia', 'media', false, false, 35, 'https://www.fci.be/en/nomenclature/BLUE-GASCONY-BASSET-35.html', 'Wikimedia Commons (CC BY-SA 3.0)', NULL, NULL, NULL, NULL, NULL, NULL, NULL),
  ('Basset Fauve De Bretagne', 'BASSET FAUVE DE BRETAGNE', 'basset-fauve-de-bretagne', 6, 'Segugi e cani per pista di sangue', NULL, 'https://upload.wikimedia.org/wikipedia/commons/thumb/a/ad/Basset_Fauve_de_Bretagne_600.jpg/500px-Basset_Fauve_de_Bretagne_600.jpg', 'Francia', 'media', false, false, 36, 'https://www.fci.be/en/nomenclature/BASSET-FAUVE-DE-BRETAGNE-36.html', 'Wikimedia Commons (CC BY-SA 3.0)', 20, 25, 12, 15, false, '{"energy": null, "trainability": null, "shedding": 3, "barking": 3, "good_with_children": 5, "good_with_other_dogs": 5}'::jsonb, NULL),
  ('Cane d''Acqua Portoghese', 'PORTUGUESE WATER DOG', 'cane-d-acqua-portoghese', 8, 'Cani da riporto', NULL, 'https://upload.wikimedia.org/wikipedia/commons/thumb/7/7a/Portuguese_Water_Dog_agility.jpg/500px-Portuguese_Water_Dog_agility.jpg', 'Portogallo', 'media', false, false, 37, 'https://www.fci.be/en/nomenclature/PORTUGUESE-WATER-DOG-37.html', 'Wikimedia Commons (CC BY 2.0)', 25, 30, 12, 15, false, '{"energy": null, "trainability": null, "shedding": 3, "barking": 3, "good_with_children": 5, "good_with_other_dogs": 3}'::jsonb, NULL),
  ('Welsh Corgi (Cardigan)', 'WELSH CORGI (CARDIGAN)', 'welsh-corgi-cardigan', 1, 'Cani da pastore e bovari', 'Il welsh corgi cardigan è un cane del gruppo pastori e bovari originario del Galles.', 'https://upload.wikimedia.org/wikipedia/commons/thumb/c/c0/Cardigan_Welsh_Corgi_600.jpg/330px-Cardigan_Welsh_Corgi_600.jpg', 'Regno Unito', 'grande', false, false, 38, 'https://www.fci.be/en/nomenclature/WELSH-CORGI-CARDIGAN-38.html', 'Wikimedia Commons (CC BY-SA)', NULL, NULL, NULL, NULL, NULL, NULL, 'https://it.wikipedia.org/wiki/Welsh_corgi_cardigan'),
  ('Welsh Corgi (Pembroke)', 'WELSH CORGI (PEMBROKE)', 'welsh-corgi-pembroke', 1, 'Cani da pastore e bovari', 'Il welsh corgi pembroke è una razza canina di origine britannica riconosciuta dalla FCI. L''area di origine della razza è il Pembrokeshire, una contea nel sud-ovest del Galles.', 'https://upload.wikimedia.org/wikipedia/commons/thumb/9/99/Welsh_Pembroke_Corgi.jpg/330px-Welsh_Pembroke_Corgi.jpg', 'Regno Unito', 'grande', false, false, 39, 'https://www.fci.be/en/nomenclature/WELSH-CORGI-PEMBROKE-39.html', 'Wikimedia Commons (CC BY-SA)', NULL, NULL, NULL, NULL, NULL, NULL, 'https://it.wikipedia.org/wiki/Welsh_corgi_pembroke'),
  ('Irish Soft Coated Wheaten Terrier', 'IRISH SOFT COATED WHEATEN TERRIER', 'irish-soft-coated-wheaten-terrier', 3, 'Terrier', 'L''Irish Soft Coated Wheaten Terrier è una razza canina appartenente alla famiglia dei Terrier. Originario dell’Irlanda, discende dal Black and Tan, Irish e il Kerry Blue Terrier.', 'https://upload.wikimedia.org/wikipedia/commons/thumb/f/fd/Soft-Coated_Wheaten_Terrier.jpg/330px-Soft-Coated_Wheaten_Terrier.jpg', 'Irlanda', 'media', false, false, 40, 'https://www.fci.be/en/nomenclature/IRISH-SOFT-COATED-WHEATEN-TERRIER-40.html', 'Wikimedia Commons (CC BY-SA)', 18, 25, 12, 15, true, NULL, 'https://it.wikipedia.org/wiki/Irish_Soft_Coated_Wheaten_Terrier'),
  ('Yugoslavian Shepherd Dog - Sharplanina', 'YUGOSLAVIAN SHEPHERD DOG - SHARPLANINA', 'yugoslavian-shepherd-dog-sharplanina', 2, 'Pinscher', NULL, 'https://upload.wikimedia.org/wikipedia/commons/thumb/e/e9/Sarplaninac_Urok1007.jpg/500px-Sarplaninac_Urok1007.jpg', 'North Macedonia', 'grande', false, false, 41, 'https://www.fci.be/en/nomenclature/YUGOSLAVIAN-SHEPHERD-DOG-SHARPLANINA-41.html', 'Wikimedia Commons (CC BY-SA 3.0)', NULL, NULL, NULL, NULL, NULL, NULL, NULL),
  ('Jämthund', 'JÄMTHUND', 'j-mthund', 5, 'Cani di tipo Spitz e primitivo', 'Lo jämthund è un cane da caccia originario del Nord Europa appartenente al gruppo degli Spitz ed è il cane nazionale della Svezia.', 'https://upload.wikimedia.org/wikipedia/commons/thumb/b/be/Swedish_Elkhound.jpg/330px-Swedish_Elkhound.jpg', 'Svezia', 'media', false, false, 42, 'https://www.fci.be/en/nomenclature/JAMTHUND-42.html', 'Wikimedia Commons (CC BY-SA)', NULL, NULL, NULL, NULL, NULL, NULL, 'https://it.wikipedia.org/wiki/J%C3%A4mthund'),
  ('Basenji', 'BASENJI', 'basenji', 5, 'Cani di tipo Spitz e primitivo', 'Il basenji è una razza di cane originaria dell''Africa. L''origine del suo nome deriva dai popoli Zande e Mangbetu della regione nord-orientale del Congo, che descrivono un Basenji, nella lingua locale Lingála, come "mbwá na basɛ́nzi", che significa "cane dei selvaggi" o "cane degli abitanti del villaggio". In Congo, il Basenji è conosciuto anche come il "cane della boscaglia".', 'https://upload.wikimedia.org/wikipedia/commons/thumb/a/a9/KinzicaGiotto_02.jpg/330px-KinzicaGiotto_02.jpg', 'Central Africa', 'media', false, false, 43, 'https://www.fci.be/en/nomenclature/BASENJI-43.html', 'Wikimedia Commons (CC BY-SA)', 9, 10, 14, 16, false, '{"energy": null, "trainability": null, "shedding": 2, "barking": 2, "good_with_children": 3, "good_with_other_dogs": 3}'::jsonb, 'https://it.wikipedia.org/wiki/Basenji'),
  ('Beauce Sheepdog', 'BEAUCE SHEEPDOG', 'beauce-sheepdog', 1, 'Cani da pastore e bovari', NULL, 'https://www.fci.be/Nomenclature/Illustrations/044g01.jpg', 'Francia', 'grande', false, false, 44, 'https://www.fci.be/en/nomenclature/BEAUCE-SHEEPDOG-44.html', 'FCI — Fédération Cynologique Internationale', NULL, NULL, NULL, NULL, NULL, NULL, NULL),
  ('Bovaro del Bernese', 'BERNESE MOUNTAIN DOG', 'bovaro-del-bernese', 2, 'Pinscher', 'Il Bovaro del Bernese è un grande cane appartenente alla categoria dei bovari svizzeri, tricolore a pelo lungo, di grossa taglia, robusto ed agile, con arti vigorosi, originario delle campagne centrali della Svizzera e delle Prealpi Bernesi.
In origine cane da guardia, traino e custodia di mandrie nel cantone di Berna, oggi è un cane di utilità e soprattutto da famiglia.', 'https://upload.wikimedia.org/wikipedia/commons/thumb/3/3f/Bovaro_del_Bernese.jpg/330px-Bovaro_del_Bernese.jpg', 'Svizzera', 'grande', false, true, 45, 'https://www.fci.be/en/nomenclature/BERNESE-MOUNTAIN-DOG-45.html', 'Wikimedia Commons (CC BY-SA)', 45, 70, 8, 10, false, '{"energy": null, "trainability": null, "shedding": 4, "barking": 3, "good_with_children": 5, "good_with_other_dogs": 5}'::jsonb, 'https://it.wikipedia.org/wiki/Bovaro_del_bernese'),
  ('Bovaro dell''Appenzell', 'APPENZELL CATTLE DOG', 'bovaro-dell-appenzell', 2, 'Pinscher', 'Il bovaro dell''Appenzell è un bovaro pluricolore a pelo corto di taglia media di origine svizzera.
Viene utilizzato come cane da pastore, da custodia e da ferma, è un cane adatto alla guardia, sicuro ed affidabile e, con i bambini, è un vero compagno di giochi.', 'https://upload.wikimedia.org/wikipedia/commons/thumb/8/83/Appenzeller_Sennenhund.JPG/330px-Appenzeller_Sennenhund.JPG', 'Svizzera', 'grande', false, false, 46, 'https://www.fci.be/en/nomenclature/APPENZELL-CATTLE-DOG-46.html', 'Wikimedia Commons (CC BY-SA)', NULL, NULL, NULL, NULL, NULL, NULL, 'https://it.wikipedia.org/wiki/Bovaro_dell''Appenzell'),
  ('Bovaro dell''Entlebuch', 'ENTLEBUCH CATTLE DOG', 'bovaro-dell-entlebuch', 2, 'Pinscher', 'Il bovaro dell''Entlebuch è una razza canina svizzera appartenente al gruppo dei bovari svizzeri.', 'https://upload.wikimedia.org/wikipedia/commons/thumb/e/e7/Entlebucher2_wb.jpg/330px-Entlebucher2_wb.jpg', 'Svizzera', 'grande', false, false, 47, 'https://www.fci.be/en/nomenclature/ENTLEBUCH-CATTLE-DOG-47.html', 'Wikimedia Commons (CC BY-SA)', NULL, NULL, NULL, NULL, NULL, NULL, 'https://it.wikipedia.org/wiki/Bovaro_dell''Entlebuch'),
