  ('Puli', 'PULI', 'puli', 1, 'Cani da pastore e bovari', 'Il puli è una razza canina ungherese riconosciuta dalla FCI.', 'https://upload.wikimedia.org/wikipedia/commons/thumb/b/b3/Puli_600.jpg/330px-Puli_600.jpg', 'Ungheria', 'grande', false, false, 55, 'https://www.fci.be/en/nomenclature/PULI-55.html', 'Wikimedia Commons (CC BY-SA)', 10, 14, 12, 15, false, '{"energy": null, "trainability": null, "shedding": 1, "barking": 3, "good_with_children": 3, "good_with_other_dogs": 3}'::jsonb, 'https://it.wikipedia.org/wiki/Puli'),
  ('Pumi', 'PUMI', 'pumi', 1, 'Cani da pastore e bovari', 'I Pumi sono un gruppo etnico facente parte dei 56 gruppi etnici riconosciuti ufficialmente dalla Repubblica Popolare Cinese. La popolazione totale conta circa 50.000 unità.', 'https://upload.wikimedia.org/wikipedia/commons/thumb/b/b3/P1090077.JPG/330px-P1090077.JPG', 'Ungheria', 'grande', false, false, 56, 'https://www.fci.be/en/nomenclature/PUMI-56.html', 'Wikimedia Commons (CC BY-SA)', 12, 16, 12, 15, false, '{"energy": null, "trainability": null, "shedding": 1, "barking": 3, "good_with_children": 3, "good_with_other_dogs": 3}'::jsonb, 'https://it.wikipedia.org/wiki/Pumi'),
  ('Vizsla Ungherese', 'HUNGARIAN SHORT-HAIRED POINTER (VIZSLA)', 'vizsla-ungherese', 7, 'Cani da ferma', NULL, 'https://upload.wikimedia.org/wikipedia/commons/thumb/2/2d/Wy%C5%BCe%C5%82_w%C4%99gierski_g%C5%82adkow%C5%82osy_500.jpg/500px-Wy%C5%BCe%C5%82_w%C4%99gierski_g%C5%82adkow%C5%82osy_500.jpg', 'Ungheria', 'grande', false, false, 57, 'https://www.fci.be/en/nomenclature/HUNGARIAN-SHORT-HAIRED-POINTER-VIZSLA-57.html', 'Wikimedia Commons (CC BY-SA 3.0)', 20, 30, 12, 14, false, NULL, NULL),
  ('Grande Bovaro Svizzero', 'GREAT SWISS MOUNTAIN DOG', 'grande-bovaro-svizzero', 2, 'Pinscher', 'Il grande bovaro svizzero è un cane di grossa taglia appartenente al Gruppo 2 della nomenclatura FCI, più precisamente alla sezione 3 - bovari svizzeri.
È il più grande di tutti e quattro i bovari svizzeri: abbastanza simile al bovaro del bernese, differisce da questi per un mantello a pelo corto e per un peso corporeo mediamente più elevato, oltre che per il carattere. Il grande bovaro era sfruttato principalmente per la guardia e la conduzione di grossi animali da fattoria e, occasionalmente, come cane da tiro per trasportare i carretti con il latte, da dove veniva prodotto a dove veniva poi lavorato.', 'https://upload.wikimedia.org/wikipedia/commons/thumb/3/32/CLINT_EASTWOOD_DI_CA%E2%80%99_DLA_PIA.jpg/330px-CLINT_EASTWOOD_DI_CA%E2%80%99_DLA_PIA.jpg', 'Svizzera', 'gigante', false, false, 58, 'https://www.fci.be/en/nomenclature/GREAT-SWISS-MOUNTAIN-DOG-58.html', 'Wikimedia Commons (CC BY-SA)', NULL, NULL, NULL, NULL, NULL, NULL, 'https://it.wikipedia.org/wiki/Grande_bovaro_svizzero'),
  ('Swiss Hound', 'SWISS HOUND', 'swiss-hound', 6, 'Segugi e cani per pista di sangue', NULL, 'https://upload.wikimedia.org/wikipedia/commons/thumb/e/eb/Go%C5%84czy_szwajcarski_2009_pl2.jpg/500px-Go%C5%84czy_szwajcarski_2009_pl2.jpg', 'Svizzera', 'media', false, false, 59, 'https://www.fci.be/en/nomenclature/SWISS-HOUND-59.html', 'Wikimedia Commons (CC BY-SA 4.0)', NULL, NULL, NULL, NULL, NULL, NULL, NULL),
