  ('Portuguese Sheepdog', 'PORTUGUESE SHEEPDOG', 'portuguese-sheepdog', 1, 'Cani da pastore e bovari', NULL, 'https://upload.wikimedia.org/wikipedia/commons/4/49/Cao_de_Serra_de_Aires600.jpg', 'Portogallo', 'grande', false, false, 93, 'https://www.fci.be/en/nomenclature/PORTUGUESE-SHEEPDOG-93.html', 'Wikimedia Commons (CC BY-SA 3.0)', 25, 30, 12, 14, false, '{"energy": null, "trainability": null, "shedding": 2, "barking": 3, "good_with_children": 3, "good_with_other_dogs": 3}'::jsonb, NULL),
