  ('Irish Red Setter', 'IRISH RED SETTER', 'irish-red-setter', 7, 'Cani da ferma', NULL, 'https://upload.wikimedia.org/wikipedia/commons/0/04/Irish_Red_And_White_Setter_2005.jpg', 'Irlanda', 'grande', false, false, 120, 'https://www.fci.be/en/nomenclature/IRISH-RED-SETTER-120.html', 'Wikimedia Commons (CC BY-SA 3.0)', NULL, NULL, NULL, NULL, NULL, NULL, NULL),
  ('Flat Coated Retriever', 'FLAT COATED RETRIEVER', 'flat-coated-retriever', 8, 'Cani da riporto', 'Il Flat-Coated Retriever è un cane da caccia facente parte del gruppo dei Retriever.', 'https://upload.wikimedia.org/wikipedia/commons/thumb/c/c1/Flatcoat_retriever_2.jpg/330px-Flatcoat_retriever_2.jpg', 'Regno Unito', 'media', false, false, 121, 'https://www.fci.be/en/nomenclature/FLAT-COATED-RETRIEVER-121.html', 'Wikimedia Commons (CC BY-SA)', NULL, NULL, NULL, NULL, NULL, '{"energy": null, "trainability": null, "shedding": 5, "barking": 3, "good_with_children": 5, "good_with_other_dogs": 5}'::jsonb, 'https://it.wikipedia.org/wiki/Flat_coated_retriever'),
  ('Labrador Retriever', 'LABRADOR RETRIEVER', 'labrador-retriever', 8, 'Cani da riporto', 'Il Labrador retriever, conosciuto più semplicemente come Labrador, è una razza canina riconosciuta solo nel 1903 dal Kennel Club, ma si hanno notizie dei loro diretti antenati già dal 1830, quando i cani d''acqua di St. John allevati da coloni europei a Terranova furono introdotti per la prima volta e successivamente selezionati in Gran Bretagna. Il Labrador fa parte del gruppo dei Retriever, cani allevati e selezionati a partire dal XIX secolo.', 'https://upload.wikimedia.org/wikipedia/commons/thumb/2/26/YellowLabradorLooking_new.jpg/330px-YellowLabradorLooking_new.jpg', 'Regno Unito', 'grande', false, true, 122, 'https://www.fci.be/en/nomenclature/LABRADOR-RETRIEVER-122.html', 'Wikimedia Commons (CC BY-SA)', 25, 32, 12, 14, false, '{"energy": null, "trainability": null, "shedding": 5, "barking": 3, "good_with_children": 5, "good_with_other_dogs": 5}'::jsonb, 'https://it.wikipedia.org/wiki/Labrador_retriever'),
  ('Field Spaniel', 'FIELD SPANIEL', 'field-spaniel', 8, 'Cani da riporto', 'Il Field Spaniel è un cane da cerca e da riporto, particolarmente adatto per la caccia su terreni accidentati. In passato considerata eccellente nel lavoro, attualmente questa razza è poco diffusa, anche nel suo Paese di origine, la Gran Bretagna.', 'https://upload.wikimedia.org/wikipedia/commons/thumb/7/78/Field_spaniel_581.jpg/330px-Field_spaniel_581.jpg', 'Regno Unito', 'media', false, false, 123, 'https://www.fci.be/en/nomenclature/FIELD-SPANIEL-123.html', 'Wikimedia Commons (CC BY-SA)', 16, 18, 12, 14, false, '{"energy": null, "trainability": null, "shedding": 5, "barking": 3, "good_with_children": 5, "good_with_other_dogs": 3}'::jsonb, 'https://it.wikipedia.org/wiki/Field_spaniel'),
  ('Irish Water Spaniel', 'IRISH WATER SPANIEL', 'irish-water-spaniel', 8, 'Cani da riporto', 'L''Irish Water Spaniel, noto per i riccioli del suo mantello, è un cane utilizzato nella caccia alla selvaggina acquatica.', 'https://upload.wikimedia.org/wikipedia/commons/thumb/6/67/Irlandzki_spaniel_wodny_676.jpg/330px-Irlandzki_spaniel_wodny_676.jpg', 'Irlanda', 'media', false, false, 124, 'https://www.fci.be/en/nomenclature/IRISH-WATER-SPANIEL-124.html', 'Wikimedia Commons (CC BY-SA)', 25, 32, 12, 14, true, '{"energy": null, "trainability": null, "shedding": 3, "barking": 2, "good_with_children": 3, "good_with_other_dogs": 3}'::jsonb, 'https://it.wikipedia.org/wiki/Irish_water_spaniel'),
  ('Springer Spaniel Inglese', 'ENGLISH SPRINGER SPANIEL', 'springer-spaniel-inglese', 8, 'Cani da riporto', 'Lo springer spaniel inglese è una razza canina di antica origine inglese. È un cane molto abile nell''acqua. Il suo modo di seguire le emanazioni della selvaggina “saltando“. Il suo modo di caccia non prevede la ferma ma scovare la selvaggina e forzarla a palesarsi, senza fermarla. Sotto questo aspetto, tutti gli spaniel sono "springer", ma questa definizione venne usata per definire il ceppo che è il capostipite di questa famiglia.', 'https://upload.wikimedia.org/wikipedia/commons/thumb/e/e5/English_Springer_in_Tallinn_4.JPG/330px-English_Springer_in_Tallinn_4.JPG', 'Regno Unito', 'media', false, false, 125, 'https://www.fci.be/en/nomenclature/ENGLISH-SPRINGER-SPANIEL-125.html', 'Wikimedia Commons (CC BY-SA)', 15, 17, 12, 14, false, '{"energy": null, "trainability": null, "shedding": 2, "barking": 3, "good_with_children": 3, "good_with_other_dogs": 3}'::jsonb, 'https://it.wikipedia.org/wiki/Springer_spaniel_inglese'),
  ('Welsh Springer Spaniel', 'WELSH SPRINGER SPANIEL', 'welsh-springer-spaniel', 8, 'Cani da riporto', NULL, 'https://upload.wikimedia.org/wikipedia/commons/thumb/a/ab/Welsh_Springer_Spaniel_1.jpg/500px-Welsh_Springer_Spaniel_1.jpg', 'Regno Unito', 'media', false, false, 126, 'https://www.fci.be/en/nomenclature/WELSH-SPRINGER-SPANIEL-126.html', 'Wikimedia Commons (CC0)', 18, 25, 12, 15, false, '{"energy": null, "trainability": null, "shedding": 3, "barking": 3, "good_with_children": 5, "good_with_other_dogs": 3}'::jsonb, NULL),
  ('Sussex Spaniel', 'SUSSEX SPANIEL', 'sussex-spaniel', 8, 'Cani da riporto', NULL, 'https://upload.wikimedia.org/wikipedia/commons/thumb/b/b7/Sussex_spaniel_276.jpg/500px-Sussex_spaniel_276.jpg', 'Regno Unito', 'media', false, false, 127, 'https://www.fci.be/en/nomenclature/SUSSEX-SPANIEL-127.html', 'Wikimedia Commons (CC BY-SA 3.0)', 18, 27, 12, 15, false, '{"energy": null, "trainability": null, "shedding": 3, "barking": 5, "good_with_children": 3, "good_with_other_dogs": 3}'::jsonb, NULL),
  ('King Charles Spaniel', 'KING CHARLES SPANIEL', 'king-charles-spaniel', 9, 'Cani da compagnia', 'King Charles Spaniel è la denominazione di una razza di cani da compagnia utilizzati, a volte, anche come cani da caccia in pianura per le loro ottime capacità visive e olfattive.', 'https://upload.wikimedia.org/wikipedia/commons/thumb/a/a7/King_charles_spaniel_Italy.jpg/330px-King_charles_spaniel_Italy.jpg', 'Regno Unito', 'piccola', false, false, 128, 'https://www.fci.be/en/nomenclature/KING-CHARLES-SPANIEL-128.html', 'Wikimedia Commons (CC BY-SA)', 5, 8, 12, 15, false, NULL, 'https://it.wikipedia.org/wiki/King_Charles_spaniel'),
