  ('Hamiltonstövare', 'HAMILTONSTÖVARE', 'hamiltonst-vare', 6, 'Segugi e cani per pista di sangue', 'Lo Hamiltonstövare è una razza di segugio svedese nata dall''incrocio del segugio tedesco con i cani inglesi foxhound e harrier. Cane molto bello e muscoloso.', 'https://upload.wikimedia.org/wikipedia/commons/thumb/5/52/Hamiltonstovare_600.jpg/330px-Hamiltonstovare_600.jpg', 'Svezia', 'media', false, false, 132, 'https://www.fci.be/en/nomenclature/HAMILTONSTOVARE-132.html', 'Wikimedia Commons (CC BY-SA)', NULL, NULL, NULL, NULL, NULL, NULL, 'https://it.wikipedia.org/wiki/Hamiltonst%C3%B6vare'),
  ('French Pointing Dog - Gascogne Type', 'FRENCH POINTING DOG - GASCOGNE TYPE', 'french-pointing-dog-gascogne-type', 7, 'Cani da ferma', NULL, 'https://upload.wikimedia.org/wikipedia/commons/thumb/8/8a/Wy%C5%BCe%C5%82_Gasko%C5%84ski.jpg/500px-Wy%C5%BCe%C5%82_Gasko%C5%84ski.jpg', 'Francia', 'grande', false, false, 133, 'https://www.fci.be/en/nomenclature/FRENCH-POINTING-DOG-GASCOGNE-TYPE-133.html', 'Wikimedia Commons (CC BY-SA 3.0)', NULL, NULL, NULL, NULL, NULL, NULL, NULL),
