  ('Lapphund Svedese', 'SWEDISH LAPPHUND', 'lapphund-svedese', 5, 'Cani di tipo Spitz e primitivo', NULL, 'https://upload.wikimedia.org/wikipedia/commons/thumb/9/9d/Swedish_Lapphund_4.jpg/500px-Swedish_Lapphund_4.jpg', 'Svezia', 'media', false, false, 135, 'https://www.fci.be/en/nomenclature/SWEDISH-LAPPHUND-135.html', 'Wikimedia Commons (CC BY-SA 4.0)', 16, 20, 12, 14, false, '{"energy": null, "trainability": null, "shedding": 3, "barking": 5, "good_with_children": 3, "good_with_other_dogs": 3}'::jsonb, NULL),
  ('Cavalier King Charles Spaniel', 'CAVALIER KING CHARLES SPANIEL', 'cavalier-king-charles-spaniel', 9, 'Cani da compagnia', 'Il Cavalier king Charles spaniel è una razza di cani di piccola taglia. È uno spaniel con un manto setoso di lunghezza media, solitamente lievemente curvato, e lunghe orecchie. La razza è stata creata nel XX secolo, nonostante abbia origine dal King Charles spaniel esistente già nel Settecento.', 'https://upload.wikimedia.org/wikipedia/commons/thumb/d/dd/Cavalier_King_Charles_Spaniels_%282821585840%29.jpg/330px-Cavalier_King_Charles_Spaniels_%282821585840%29.jpg', 'Regno Unito', 'piccola', false, true, 136, 'https://www.fci.be/en/nomenclature/CAVALIER-KING-CHARLES-SPANIEL-136.html', 'Wikimedia Commons (CC BY-SA)', 5, 8, 12, 15, false, '{"energy": null, "trainability": null, "shedding": 2, "barking": 3, "good_with_children": 5, "good_with_other_dogs": 5}'::jsonb, 'https://it.wikipedia.org/wiki/Cavalier_King_Charles_spaniel'),
  ('Pyrenean Mountain Dog', 'PYRENEAN MOUNTAIN DOG', 'pyrenean-mountain-dog', 2, 'Pinscher', NULL, 'https://upload.wikimedia.org/wikipedia/commons/thumb/a/a3/Pyrenean_Mountain_Dog_600.jpg/500px-Pyrenean_Mountain_Dog_600.jpg', 'Francia', 'grande', false, false, 137, 'https://www.fci.be/en/nomenclature/PYRENEAN-MOUNTAIN-DOG-137.html', 'Wikimedia Commons (CC BY-SA 3.0)', NULL, NULL, NULL, NULL, NULL, NULL, NULL),
  ('Pyrenean Sheepdog - Smooth Faced', 'PYRENEAN SHEEPDOG - SMOOTH FACED', 'pyrenean-sheepdog-smooth-faced', 1, 'Cani da pastore e bovari', NULL, 'https://upload.wikimedia.org/wikipedia/commons/thumb/5/5d/Berger-des-Pyrenees_Ellea_800x600.jpg/500px-Berger-des-Pyrenees_Ellea_800x600.jpg', 'Francia', 'grande', false, false, 138, 'https://www.fci.be/en/nomenclature/PYRENEAN-SHEEPDOG-SMOOTH-FACED-138.html', 'Wikimedia Commons (CC BY-SA 3.0)', NULL, NULL, NULL, NULL, NULL, NULL, NULL),
  ('Terrier Irlandese', 'IRISH TERRIER', 'terrier-irlandese', 3, 'Terrier', NULL, 'https://upload.wikimedia.org/wikipedia/commons/thumb/9/97/Irish_Terrier_CR.jpg/500px-Irish_Terrier_CR.jpg', 'Irlanda', 'media', false, false, 139, 'https://www.fci.be/en/nomenclature/IRISH-TERRIER-139.html', 'Wikimedia Commons (CC BY-SA 3.0)', 7, 9, 12, 15, false, '{"energy": null, "trainability": null, "shedding": 2, "barking": 3, "good_with_children": 5, "good_with_other_dogs": 1}'::jsonb, NULL),
  ('Boston Terrier', 'BOSTON TERRIER', 'boston-terrier', 9, 'Cani da compagnia', 'Il Boston Terrier è una razza canina originaria degli Stati Uniti e riconosciuta dalla FCI, molto simile al Bouledogue français.', 'https://upload.wikimedia.org/wikipedia/commons/thumb/6/66/BostonTerrierBrindleStand_w.jpg/330px-BostonTerrierBrindleStand_w.jpg', 'United States Of America', 'piccola', false, false, 140, 'https://www.fci.be/en/nomenclature/BOSTON-TERRIER-140.html', 'Wikimedia Commons (CC BY-SA)', 5, 11, 12, 14, false, '{"energy": null, "trainability": null, "shedding": 1, "barking": 1, "good_with_children": 5, "good_with_other_dogs": 3}'::jsonb, 'https://it.wikipedia.org/wiki/Boston_Terrier'),
  ('Long-Haired Pyrenean Sheepdog', 'LONG-HAIRED PYRENEAN SHEEPDOG', 'long-haired-pyrenean-sheepdog', 1, 'Cani da pastore e bovari', NULL, 'https://upload.wikimedia.org/wikipedia/commons/5/50/Berger-des-Pyrenees_Adeux_0302x0214.jpg', 'Francia', 'grande', false, false, 141, 'https://www.fci.be/en/nomenclature/LONG-HAIRED-PYRENEAN-SHEEPDOG-141.html', 'Wikimedia Commons (CC BY-SA 3.0)', NULL, NULL, NULL, NULL, NULL, NULL, NULL),
  ('Slovakian Chuvach', 'SLOVAKIAN CHUVACH', 'slovakian-chuvach', 1, 'Cani da pastore e bovari', NULL, 'https://upload.wikimedia.org/wikipedia/commons/thumb/c/c6/Cuvac_1.jpg/500px-Cuvac_1.jpg', 'Slovacchia', 'grande', false, false, 142, 'https://www.fci.be/en/nomenclature/SLOVAKIAN-CHUVACH-142.html', 'Wikimedia Commons (CC BY-SA 3.0)', NULL, NULL, NULL, NULL, NULL, NULL, NULL),
  ('Dobermann', 'DOBERMANN', 'dobermann', 2, 'Pinscher', 'Il Dobermann è una razza selezionata dall''uomo, riconosciuta dalla FCI. Il nome deriva dal cognome del tedesco Friedrich Louis Dobermann, che la creò nel 1890.', 'https://upload.wikimedia.org/wikipedia/commons/thumb/6/6a/Jean_Dark_Sn%C3%B6_of_Sweden.jpg/330px-Jean_Dark_Sn%C3%B6_of_Sweden.jpg', 'Germania', 'grande', false, true, 143, 'https://www.fci.be/en/nomenclature/DOBERMANN-143.html', 'Wikimedia Commons (CC BY-SA)', NULL, NULL, NULL, NULL, NULL, NULL, 'https://it.wikipedia.org/wiki/Dobermann'),
  ('Boxer', 'BOXER', 'boxer', 2, 'Pinscher', NULL, 'https://upload.wikimedia.org/wikipedia/commons/thumb/c/c2/Deutscher_Boxer_Elmo_vom_Freudenreich.jpg/500px-Deutscher_Boxer_Elmo_vom_Freudenreich.jpg', 'Germania', 'grande', false, true, 144, 'https://www.fci.be/en/nomenclature/BOXER-144.html', 'Wikimedia Commons (CC BY 4.0)', 25, 32, 10, 12, false, '{"energy": null, "trainability": null, "shedding": 2, "barking": 3, "good_with_children": 5, "good_with_other_dogs": 3}'::jsonb, NULL),
  ('Leonberger', 'LEONBERGER', 'leonberger', 2, 'Pinscher', 'Il leonberger è una razza di cani originaria di Leonberg, piccola cittadina del Baden-Württemberg, in Germania. La sua origine esatta rimane incerta ma Heinrich Essig, considerato il padre della razza, sostenne di aver ottenuto il Leonberger incrociando esemplari di varie razze tra cui San Bernardo, Terranova e Cane da Montagna dei Pirenei.', 'https://upload.wikimedia.org/wikipedia/commons/thumb/d/d9/Leonberg-Male-Adulte-Ursus.jpg/330px-Leonberg-Male-Adulte-Ursus.jpg', 'Germania', 'gigante', false, true, 145, 'https://www.fci.be/en/nomenclature/LEONBERGER-145.html', 'Wikimedia Commons (CC BY-SA)', 70, 80, 8, 10, false, '{"energy": null, "trainability": null, "shedding": 5, "barking": 3, "good_with_children": 5, "good_with_other_dogs": 3}'::jsonb, 'https://it.wikipedia.org/wiki/Leonberger'),
  ('Rhodesian Ridgeback', 'RHODESIAN RIDGEBACK', 'rhodesian-ridgeback', 6, 'Segugi e cani per pista di sangue', 'Il Rhodesian Ridgeback è un cane di taglia grande, a pelo raso, di colore marrone. La particolarità di questa razza è la cresta sul dorso (ridge), formata da pelo che cresce in direzione opposta al resto del mantello. È una delle principali razze crestate, le altre sono il Phu Quoc Ridgeback e il Thai Ridgeback.', 'https://upload.wikimedia.org/wikipedia/commons/thumb/d/df/Akani_Stehbild.JPG/330px-Akani_Stehbild.JPG', 'Sudafrica', 'grande', false, false, 146, 'https://www.fci.be/en/nomenclature/RHODESIAN-RIDGEBACK-146.html', 'Wikimedia Commons (CC BY-SA)', 34, 41, 12, 14, false, '{"energy": null, "trainability": null, "shedding": 3, "barking": 1, "good_with_children": 5, "good_with_other_dogs": 3}'::jsonb, 'https://it.wikipedia.org/wiki/Rhodesian_ridgeback'),
  ('Rottweiler', 'ROTTWEILER', 'rottweiler', 2, 'Pinscher', 'Il Rottweiler è una razza canina molossoide selezionata nella cittadina tedesca di Rottweil sul fiume Neckar nel corso del XIX secolo, dove questo cane era utilizzato per la custodia delle carni dei macellai e per il traino di piccoli carri utilizzati per il trasporto delle merci.', 'https://upload.wikimedia.org/wikipedia/commons/thumb/f/f9/%22Prince%22_%287216225820%29.jpg/330px-%22Prince%22_%287216225820%29.jpg', 'Germania', 'grande', false, true, 147, 'https://www.fci.be/en/nomenclature/ROTTWEILER-147.html', 'Wikimedia Commons (CC BY-SA)', 50, 60, 8, 10, false, '{"energy": null, "trainability": null, "shedding": 3, "barking": 2, "good_with_children": 3, "good_with_other_dogs": 3}'::jsonb, 'https://it.wikipedia.org/wiki/Rottweiler'),
  ('Bassotto', 'DACHSHUND', 'bassotto', 4, 'Bassotti', 'Il bassotto tedesco è una razza canina caratterizzata dall''altezza proporzionalmente inferiore alla lunghezza. Si tratta di un cane da caccia e da compagnia, adatto per seguire gli animali selvatici nel sottobosco e affrontarli anche nelle tane sotterranee.', 'https://upload.wikimedia.org/wikipedia/commons/thumb/f/f4/MiniDachshund1_wb.jpg/330px-MiniDachshund1_wb.jpg', 'Germania', 'piccola', false, false, 148, 'https://www.fci.be/en/nomenclature/DACHSHUND-148.html', 'Wikimedia Commons (CC BY-SA)', 5, 9, 12, 15, false, '{"energy": null, "trainability": null, "shedding": 5, "barking": 4, "good_with_children": 3, "good_with_other_dogs": 3}'::jsonb, 'https://it.wikipedia.org/wiki/Bassotto_tedesco'),
