  ('Bullmastiff', 'BULLMASTIFF', 'bullmastiff', 2, 'Pinscher', 'Il bullmastiff è una razza canina di origine britannica riconosciuta dalla FCI.', 'https://upload.wikimedia.org/wikipedia/commons/thumb/5/5c/Dog_Bullmastiff_600.jpg/330px-Dog_Bullmastiff_600.jpg', 'Regno Unito', 'gigante', false, false, 157, 'https://www.fci.be/en/nomenclature/BULLMASTIFF-157.html', 'Wikimedia Commons (CC BY-SA)', 50, 59, 8, 10, false, '{"energy": null, "trainability": null, "shedding": 3, "barking": 2, "good_with_children": 3, "good_with_other_dogs": 3}'::jsonb, 'https://it.wikipedia.org/wiki/Bullmastiff'),
  ('Greyhound', 'GREYHOUND', 'greyhound', 10, 'Levrieri', 'Il greyhound è una razza canina appartenente al gruppo dei levrieri; è quindi un cane da caccia a vista.', 'https://upload.wikimedia.org/wikipedia/commons/thumb/e/ef/GraceTheGreyhound.jpg/330px-GraceTheGreyhound.jpg', 'Regno Unito', 'media', false, false, 158, 'https://www.fci.be/en/nomenclature/GREYHOUND-158.html', 'Wikimedia Commons (CC BY-SA)', 25, 40, 10, 12, false, '{"energy": null, "trainability": null, "shedding": 2, "barking": 3, "good_with_children": 3, "good_with_other_dogs": 3}'::jsonb, 'https://it.wikipedia.org/wiki/Greyhound'),
  ('Foxhound Inglese', 'ENGLISH FOXHOUND', 'foxhound-inglese', 6, 'Segugi e cani per pista di sangue', NULL, 'https://upload.wikimedia.org/wikipedia/commons/thumb/4/44/English_Foxhound_portrait.jpg/500px-English_Foxhound_portrait.jpg', 'Regno Unito', 'media', false, false, 159, 'https://www.fci.be/en/nomenclature/ENGLISH-FOXHOUND-159.html', 'Wikimedia Commons (CC BY 2.0)', 25, 29, 12, 15, false, '{"energy": null, "trainability": null, "shedding": 5, "barking": 4, "good_with_children": 5, "good_with_other_dogs": 5}'::jsonb, NULL),
  ('Levriero Irlandese', 'IRISH WOLFHOUND', 'levriero-irlandese', 10, 'Levrieri', NULL, 'https://upload.wikimedia.org/wikipedia/commons/b/b8/IrishWolfhoundPair.jpg', 'Irlanda', 'gigante', false, false, 160, 'https://www.fci.be/en/nomenclature/IRISH-WOLFHOUND-160.html', 'Wikimedia Commons (CC BY-SA 3.0)', 45, 90, 6, 8, false, '{"energy": null, "trainability": null, "shedding": 3, "barking": 2, "good_with_children": 3, "good_with_other_dogs": 3}'::jsonb, NULL),
  ('Beagle', 'BEAGLE', 'beagle', 6, 'Segugi e cani per pista di sangue', NULL, 'https://upload.wikimedia.org/wikipedia/commons/thumb/d/d7/PAT_Beagle.jpg/500px-PAT_Beagle.jpg', 'Regno Unito', 'media', false, true, 161, 'https://www.fci.be/en/nomenclature/BEAGLE-161.html', 'Wikimedia Commons (CC BY-SA 4.0)', 9, 11, 12, 15, false, '{"energy": null, "trainability": null, "shedding": 2, "barking": 5, "good_with_children": 5, "good_with_other_dogs": 5}'::jsonb, NULL),
  ('Whippet', 'WHIPPET', 'whippet', 10, 'Levrieri', 'Il Whippet è una razza canina britannica riconosciuta dalla FCI.', 'https://upload.wikimedia.org/wikipedia/commons/thumb/5/5e/WhippetWhiteSaddled_wb.jpg/330px-WhippetWhiteSaddled_wb.jpg', 'Regno Unito', 'media', false, false, 162, 'https://www.fci.be/en/nomenclature/WHIPPET-162.html', 'Wikimedia Commons (CC BY-SA)', 10, 15, 12, 15, false, '{"energy": null, "trainability": null, "shedding": 2, "barking": 2, "good_with_children": 5, "good_with_other_dogs": 5}'::jsonb, 'https://it.wikipedia.org/wiki/Whippet'),
  ('Basset Hound', 'BASSET HOUND', 'basset-hound', 6, 'Segugi e cani per pista di sangue', 'Il Basset hound è una razza di cane originaria dell''Europa, il cui nome deriva dall''unione del termine francese bas (bassetto), e dalla parola inglese hound (segugio).', 'https://upload.wikimedia.org/wikipedia/commons/thumb/7/7e/Basset_Hound_600.jpg/330px-Basset_Hound_600.jpg', 'Regno Unito', 'media', false, false, 163, 'https://www.fci.be/en/nomenclature/BASSET-HOUND-163.html', 'Wikimedia Commons (CC BY-SA)', 20, 29, 12, 14, false, '{"energy": null, "trainability": null, "shedding": 2, "barking": 5, "good_with_children": 5, "good_with_other_dogs": 5}'::jsonb, 'https://it.wikipedia.org/wiki/Basset_hound'),
  ('Deerhound', 'DEERHOUND', 'deerhound', 10, 'Levrieri', 'Il Deerhound chiamato anche Levriero scozzese è una razza canina di origine inglese riconosciuta dalla FCI. È un cane rustico e solido, abilissimo nella caccia agli ungulati di grosse dimensioni, estremamente docile e dal comportamento quasi timido nei confronti dell''uomo.', 'https://upload.wikimedia.org/wikipedia/commons/thumb/5/52/Hilton_of_cadboll_stone_Andrew_Gibb_1856_bis.jpg/330px-Hilton_of_cadboll_stone_Andrew_Gibb_1856_bis.jpg', 'Regno Unito', 'media', false, false, 164, 'https://www.fci.be/en/nomenclature/DEERHOUND-164.html', 'Wikimedia Commons (CC BY-SA)', 35, 50, 8, 10, false, NULL, 'https://it.wikipedia.org/wiki/Deerhound'),
  ('Spinone Italiano', 'ITALIAN SPINONE', 'spinone-italiano', 7, 'Cani da ferma', 'Lo spinone italiano è una razza canina di origine italiana.', 'https://upload.wikimedia.org/wikipedia/commons/thumb/1/1b/05042333_Spinone_weiss.jpg/330px-05042333_Spinone_weiss.jpg', 'Italia', 'grande', true, true, 165, 'https://www.fci.be/en/nomenclature/ITALIAN-SPINONE-165.html', 'Wikimedia Commons (CC BY-SA)', 30, 35, 12, 14, false, NULL, 'https://it.wikipedia.org/wiki/Spinone_italiano'),
  ('Pastore Tedesco', 'GERMAN SHEPHERD DOG', 'pastore-tedesco', 1, 'Cani da pastore e bovari', 'Il cane da pastore tedesco, comunemente abbreviato in pastore tedesco e talvolta detto cane lupo e cane poliziotto, secondo la classificazione cinologica FCI risponde allo standard nr. 166/10.08.2010-D (D=Germania); appartiene al 1º gruppo di razze canine con riferimento alla sezione 1, cani da pastore con brevetto da lavoro e impiego come cane da utilità, da difesa e per usi molteplici.', 'https://upload.wikimedia.org/wikipedia/commons/thumb/4/4f/German-shepherd-4040871920._%282%29.jpg/330px-German-shepherd-4040871920._%282%29.jpg', 'Germania', 'grande', false, true, 166, 'https://www.fci.be/en/nomenclature/GERMAN-SHEPHERD-DOG-166.html', 'Wikimedia Commons (CC BY-SA)', 30, 40, 9, 13, false, '{"energy": null, "trainability": null, "shedding": 5, "barking": 3, "good_with_children": 5, "good_with_other_dogs": 3}'::jsonb, 'https://it.wikipedia.org/wiki/Cane_da_pastore_tedesco'),
  ('Cocker Spaniel Americano', 'AMERICAN COCKER SPANIEL', 'cocker-spaniel-americano', 8, 'Cani da riporto', NULL, 'https://upload.wikimedia.org/wikipedia/commons/thumb/a/aa/AmericanCockerSpaniel_wb.jpg/500px-AmericanCockerSpaniel_wb.jpg', 'United States Of America', 'media', false, false, 167, 'https://www.fci.be/en/nomenclature/AMERICAN-COCKER-SPANIEL-167.html', 'Wikimedia Commons (CC BY-SA 3.0)', 11, 15, 12, 15, false, NULL, NULL),
  ('Dandie Dinmont Terrier', 'DANDIE DINMONT TERRIER', 'dandie-dinmont-terrier', 3, 'Terrier', NULL, 'https://upload.wikimedia.org/wikipedia/commons/thumb/6/63/Dandie_Dinmont_Terrier_600.jpg/500px-Dandie_Dinmont_Terrier_600.jpg', 'Regno Unito', 'media', false, false, 168, 'https://www.fci.be/en/nomenclature/DANDIE-DINMONT-TERRIER-168.html', 'Wikimedia Commons (CC BY-SA 3.0)', 8, 11, 12, 14, false, '{"energy": null, "trainability": null, "shedding": 1, "barking": 3, "good_with_children": 3, "good_with_other_dogs": 3}'::jsonb, NULL),
  ('Fox Terrier a pelo duro', 'FOX TERRIER (WIRE)', 'fox-terrier-a-pelo-duro', 3, 'Terrier', NULL, 'https://upload.wikimedia.org/wikipedia/commons/thumb/4/45/Wire_fox_terrier_portrait_03.jpg/500px-Wire_fox_terrier_portrait_03.jpg', 'Regno Unito', 'media', false, false, 169, 'https://www.fci.be/en/nomenclature/FOX-TERRIER-WIRE-169.html', 'Wikimedia Commons (CC BY 2.0)', NULL, NULL, NULL, NULL, NULL, NULL, NULL),
  ('Castro Laboreiro Dog', 'CASTRO LABOREIRO DOG', 'castro-laboreiro-dog', 2, 'Pinscher', NULL, 'https://upload.wikimedia.org/wikipedia/commons/thumb/f/f2/C%C3%A3o_de_Castro_Laboreiro_em_Entalada%2C_Castro_Laboreiro.jpg/500px-C%C3%A3o_de_Castro_Laboreiro_em_Entalada%2C_Castro_Laboreiro.jpg', 'Portogallo', 'grande', false, false, 170, 'https://www.fci.be/en/nomenclature/CASTRO-LABOREIRO-DOG-170.html', 'Wikimedia Commons (CC BY-SA 2.0)', NULL, NULL, NULL, NULL, NULL, NULL, NULL),
  ('Bouvier Des Ardennes', 'BOUVIER DES ARDENNES', 'bouvier-des-ardennes', 1, 'Cani da pastore e bovari', NULL, 'https://upload.wikimedia.org/wikipedia/commons/thumb/f/f8/Bouvier_des_Ardennes_1.JPG/500px-Bouvier_des_Ardennes_1.JPG', 'Belgio', 'grande', false, false, 171, 'https://www.fci.be/en/nomenclature/BOUVIER-DES-ARDENNES-171.html', 'Wikimedia Commons (CC BY-SA 3.0)', NULL, NULL, NULL, NULL, NULL, NULL, NULL),
  ('Barboncino', 'POODLE', 'barboncino', 9, 'Cani da compagnia', 'Il barbone, comunemente chiamato barboncino, è una razza canina di origine francese e tedesca. In passato, grazie al suo fiuto e alla sua propensione per l''acqua, era impiegato nella caccia alle anatre come cane da riporto. Il suo nome francese, caniche, deriverebbe infatti da canard (anatra) o da chien canne. Il termine tedesco Pudel, da cui l''inglese poodle, trae invece origine dal tedesco arcaico pudeln, che significa letteralmente «tuffarsi». A dispetto di quello che fu per secoli il suo utilizzo prevalente, il barbone è oggi inserito nel IX gruppo della classificazione FCI, ovvero la categoria dei cani da compagnia.', 'https://upload.wikimedia.org/wikipedia/commons/thumb/b/b6/Pudel_Klein_apricotred.jpg/330px-Pudel_Klein_apricotred.jpg', 'Francia', 'piccola', false, true, 172, 'https://www.fci.be/en/nomenclature/POODLE-172.html', 'Wikimedia Commons (CC BY-SA)', 4, 7, 14, 16, false, NULL, 'https://it.wikipedia.org/wiki/Barbone_(razza_canina)'),
