  ('Shih Tzu', 'SHIH TZU', 'shih-tzu', 9, 'Cani da compagnia', 'Lo Shih Tzu è una razza canina di origine cinese riconosciuta dalla FCI.', 'https://upload.wikimedia.org/wikipedia/commons/thumb/4/49/Black_and_White_Shih_Tzu.jpg/330px-Black_and_White_Shih_Tzu.jpg', 'Tibet (China)', 'piccola', false, true, 208, 'https://www.fci.be/en/nomenclature/SHIH-TZU-208.html', 'Wikimedia Commons (CC BY-SA)', 4, 7, 14, 16, false, '{"energy": null, "trainability": null, "shedding": 1, "barking": 3, "good_with_children": 5, "good_with_other_dogs": 5}'::jsonb, 'https://it.wikipedia.org/wiki/Shih_Tzu'),
  ('Tibetan Terrier', 'TIBETAN TERRIER', 'tibetan-terrier', 9, 'Cani da compagnia', 'Il Tibetan Terrier è una razza razza canina originaria del Tibet, dove nel corso di molti secoli venne allevata e tenuta in grande considerazione sia dal popolo che dalla nobiltà, che le attribuivano caratteri di cane sacro e portafortuna.', 'https://upload.wikimedia.org/wikipedia/commons/thumb/8/89/Tibet_Terrier_Bennie.jpg/330px-Tibet_Terrier_Bennie.jpg', 'Tibet (China)', 'piccola', false, false, 209, 'https://www.fci.be/en/nomenclature/TIBETAN-TERRIER-209.html', 'Wikimedia Commons (CC BY-SA)', 6, 8, 14, 16, false, '{"energy": null, "trainability": null, "shedding": 1, "barking": 3, "good_with_children": 3, "good_with_other_dogs": 3}'::jsonb, 'https://it.wikipedia.org/wiki/Tibetan_Terrier'),
  ('Canadian Eskimo Dog', 'CANADIAN ESKIMO DOG', 'canadian-eskimo-dog', 5, 'Cani di tipo Spitz e primitivo', 'Il canadian eskimo dog è un cane da slitta di origini antiche, certamente derivato dal lupo artico che ha permesso alle popolazioni esquimesi del Canada artico di sopravvivere per secoli in quell''ambiente ostile.', 'https://upload.wikimedia.org/wikipedia/commons/d/d3/Canadian_Inuit_Dog.jpg', 'Canada', 'media', false, false, 211, 'https://www.fci.be/en/nomenclature/CANADIAN-ESKIMO-DOG-211.html', 'Wikimedia Commons (CC BY-SA)', NULL, NULL, NULL, NULL, NULL, '{"energy": null, "trainability": null, "shedding": null, "barking": null, "good_with_children": 3, "good_with_other_dogs": 3}'::jsonb, 'https://it.wikipedia.org/wiki/Canadian_Eskimo_Dog'),
  ('Samoiedo', 'SAMOYED', 'samoiedo', 5, 'Cani di tipo Spitz e primitivo', 'Il samoiedo è una razza canina che prende il nome da un termine obsoleto usato per indicare, tra gli altri, il popolo dei Nenci, che vive in alcune aree della Siberia. Pastori nomadi di renne, allevano questo bianco, soffice e allegro cane per aiutarli nel lavoro. Nel 1896 i coniugi inglesi Kilburn-Scott iniziarono a dedicare la loro vita alla ricerca e alla formazione del samoiedo moderno, attraverso una selezione mirata alla produzione di soggetti da esibizione, con l''intento soprattutto di fissare il colore bianco puro.', 'https://upload.wikimedia.org/wikipedia/commons/thumb/f/f6/11.10.2015_Samoyed_%28cropped%29.jpg/330px-11.10.2015_Samoyed_%28cropped%29.jpg', 'Northern Russia', 'grande', false, true, 212, 'https://www.fci.be/en/nomenclature/SAMOYED-212.html', 'Wikimedia Commons (CC BY-SA)', 20, 30, 12, 14, false, '{"energy": null, "trainability": null, "shedding": 3, "barking": 4, "good_with_children": 5, "good_with_other_dogs": 3}'::jsonb, 'https://it.wikipedia.org/wiki/Samoiedo'),
  ('Hanoverian Scent Hound', 'HANOVERIAN SCENT HOUND', 'hanoverian-scent-hound', 6, 'Segugi e cani per pista di sangue', NULL, 'https://www.fci.be/Nomenclature/Illustrations/213g06-1.jpg', 'Germania', 'media', false, false, 213, 'https://www.fci.be/en/nomenclature/HANOVERIAN-SCENT-HOUND-213.html', 'FCI — Fédération Cynologique Internationale', NULL, NULL, NULL, NULL, NULL, NULL, NULL),
  ('Hellenic Hound', 'HELLENIC HOUND', 'hellenic-hound', 6, 'Segugi e cani per pista di sangue', NULL, 'https://upload.wikimedia.org/wikipedia/commons/thumb/6/6d/Hellinikos_Ichnilatis_%28Georging%29_cropped.jpg/500px-Hellinikos_Ichnilatis_%28Georging%29_cropped.jpg', 'Grecia', 'media', false, false, 214, 'https://www.fci.be/en/nomenclature/HELLENIC-HOUND-214.html', 'Wikimedia Commons (CC BY-SA 3.0)', NULL, NULL, NULL, NULL, NULL, NULL, NULL),
  ('Bichon Frisé', 'BICHON FRISE', 'bichon-frise', 9, 'Cani da compagnia', 'Il Bichon à poil frisé è una razza canina riconosciuta dalla FCI.', 'https://upload.wikimedia.org/wikipedia/commons/thumb/6/64/Bichon_Frise_600.jpg/330px-Bichon_Frise_600.jpg', 'Belgium', 'piccola', false, true, 215, 'https://www.fci.be/en/nomenclature/BICHON-FRISE-215.html', 'Wikimedia Commons (CC BY-SA)', 3, 5, 14, 16, true, '{"energy": null, "trainability": null, "shedding": 1, "barking": 3, "good_with_children": 5, "good_with_other_dogs": 5}'::jsonb, 'https://it.wikipedia.org/wiki/Bichon_%C3%A0_poil_fris%C3%A9'),
  ('Pudelpointer', 'PUDELPOINTER', 'pudelpointer', 7, 'Cani da ferma', 'Il Pudelpointer è un cane da ferma a pelo duro, adatto sia per la caccia in pianura che in quella nel bosco o in acqua.', 'https://upload.wikimedia.org/wikipedia/commons/thumb/0/05/Pudelpointer_on_point.jpg/330px-Pudelpointer_on_point.jpg', 'Germania', 'grande', false, false, 216, 'https://www.fci.be/en/nomenclature/PUDELPOINTER-216.html', 'Wikimedia Commons (CC BY-SA)', 25, 30, 12, 15, false, '{"energy": null, "trainability": null, "shedding": 3, "barking": 3, "good_with_children": 3, "good_with_other_dogs": 3}'::jsonb, 'https://it.wikipedia.org/wiki/Pudelpointer'),
