  ('Fila Brasileiro', 'FILA BRASILEIRO', 'fila-brasileiro', 2, 'Pinscher', 'Il fila brasileiro è una razza canina di origine brasiliana dal forte temperamento e grande devozione al padrone.', 'https://upload.wikimedia.org/wikipedia/commons/2/26/Fila_Brasileiro_%28dog%29.jpg', 'Brasile', 'gigante', false, false, 225, 'https://www.fci.be/en/nomenclature/FILA-BRASILEIRO-225.html', 'Wikimedia Commons (CC BY-SA)', NULL, NULL, NULL, NULL, NULL, NULL, 'https://it.wikipedia.org/wiki/Fila_brasileiro'),
