  ('Mudi', 'MUDI', 'mudi', 1, 'Cani da pastore e bovari', 'Il mudi è una razza canina ungherese riconosciuta dalla FCI.', 'https://upload.wikimedia.org/wikipedia/commons/thumb/c/c4/Hondenras_Mudi.jpg/330px-Hondenras_Mudi.jpg', 'Ungheria', 'grande', false, false, 238, 'https://www.fci.be/en/nomenclature/MUDI-238.html', 'Wikimedia Commons (CC BY-SA)', 10, 15, 12, 15, false, '{"energy": null, "trainability": null, "shedding": 2, "barking": 5, "good_with_children": 3, "good_with_other_dogs": 3}'::jsonb, 'https://it.wikipedia.org/wiki/Mudi'),
