  ('Akita Inu', 'AKITA', 'akita-inu', 5, 'Cani di tipo Spitz e primitivo', 'L''akita  è una razza giapponese di cani da lavoro, utilizzati sia per la guardia sia per la caccia.', 'https://upload.wikimedia.org/wikipedia/commons/thumb/a/a7/Akita_Inu_dog.jpg/330px-Akita_Inu_dog.jpg', 'Giappone', 'media', false, true, 255, 'https://www.fci.be/en/nomenclature/AKITA-255.html', 'Wikimedia Commons (CC BY-SA)', 35, 60, 10, 12, false, '{"energy": null, "trainability": null, "shedding": 3, "barking": 1, "good_with_children": 3, "good_with_other_dogs": 1}'::jsonb, 'https://it.wikipedia.org/wiki/Akita_(razza_canina)'),
  ('Shiba Inu', 'SHIBA', 'shiba-inu', 5, 'Cani di tipo Spitz e primitivo', 'Lo shiba inu è una razza canina di origine giapponese riconosciuta dalla FCI', 'https://upload.wikimedia.org/wikipedia/commons/thumb/5/58/Shiba_inu_taiki.jpg/330px-Shiba_inu_taiki.jpg', 'Giappone', 'media', false, true, 257, 'https://www.fci.be/en/nomenclature/SHIBA-257.html', 'Wikimedia Commons (CC BY-SA)', 9, 10, 12, 15, false, NULL, 'https://it.wikipedia.org/wiki/Shiba_(razza_canina)'),
