  ('Tosa', 'TOSA', 'tosa', 2, 'Pinscher', 'Tosa  è una città giapponese della prefettura di Kōchi.', 'https://upload.wikimedia.org/wikipedia/commons/thumb/8/8c/Flag_of_Tosa%2C_Kochi.svg/langit-330px-Flag_of_Tosa%2C_Kochi.svg.png', 'Giappone', 'grande', false, false, 260, 'https://www.fci.be/en/nomenclature/TOSA-260.html', 'Wikimedia Commons (CC BY-SA)', 50, 80, 8, 12, false, '{"energy": null, "trainability": null, "shedding": 2, "barking": 3, "good_with_children": 3, "good_with_other_dogs": 1}'::jsonb, 'https://it.wikipedia.org/wiki/Tosa'),
  ('Hokkaido', 'HOKKAIDO', 'hokkaido', 5, 'Cani di tipo Spitz e primitivo', 'Hokkaidō  è una delle otto regioni del Giappone, situata direttamente a nord dell''isola principale dell''arcipelago nipponico, Honshū. È la più settentrionale delle cinque isole maggiori che compongono l''arcipelago giapponese e la meno urbanizzata.', 'https://upload.wikimedia.org/wikipedia/commons/thumb/a/a5/Satellite_image_of_Hokkaido%2C_Japan_in_May_2001.jpg/330px-Satellite_image_of_Hokkaido%2C_Japan_in_May_2001.jpg', 'Giappone', 'media', false, false, 261, 'https://www.fci.be/en/nomenclature/HOKKAIDO-261.html', 'Wikimedia Commons (CC BY-SA)', 20, 30, 12, 15, false, '{"energy": null, "trainability": null, "shedding": 3, "barking": 3, "good_with_children": 3, "good_with_other_dogs": 3}'::jsonb, 'https://it.wikipedia.org/wiki/Hokkaid%C5%8D'),
