  ('Thai Ridgeback Dog', 'THAI RIDGEBACK DOG', 'thai-ridgeback-dog', 5, 'Cani di tipo Spitz e primitivo', 'Il Thai Ridgeback Dog è un cane di taglia media originario della Thailandia, riconosciuto dalla FCI. La razza, precedentemente sconosciuta al di fuori dello Stato, sta acquisendo popolarità nel mondo occidentale. Il Thai Ridgeback è una delle principali razze di cani crestati, che hanno una cresta di peli che corre lungo la schiena nella direzione opposta rispetto al resto del mantello, assieme al Rhodesian ridgeback e al Phu Quoc Ridgeback.', 'https://upload.wikimedia.org/wikipedia/commons/thumb/d/d6/Thai-Ridgeback.jpg/330px-Thai-Ridgeback.jpg', 'Thailand', 'media', false, false, 338, 'https://www.fci.be/en/nomenclature/THAI-RIDGEBACK-DOG-338.html', 'Wikimedia Commons (CC BY-SA)', 20, 25, 12, 14, false, NULL, 'https://it.wikipedia.org/wiki/Thai_Ridgeback_Dog'),
  ('Parson Russell Terrier', 'PARSON RUSSELL TERRIER', 'parson-russell-terrier', 3, 'Terrier', 'Il Parson Russell Terrier è una razza canina britannica riconosciuta dalla FCI, discendente dal Fox Terrier fu selezionata dal reverendo John Russell nel diciannovesimo secolo.', 'https://upload.wikimedia.org/wikipedia/commons/thumb/5/5b/Tinodopp.jpg/330px-Tinodopp.jpg', 'Regno Unito', 'media', false, false, 339, 'https://www.fci.be/en/nomenclature/PARSON-RUSSELL-TERRIER-339.html', 'Wikimedia Commons (CC BY-SA)', 6, 8, 12, 14, false, '{"energy": null, "trainability": null, "shedding": 2, "barking": 3, "good_with_children": 3, "good_with_other_dogs": 5}'::jsonb, 'https://it.wikipedia.org/wiki/Parson_Russell_terrier'),
  ('Saint Miguel Cattle Dog', 'SAINT MIGUEL CATTLE DOG', 'saint-miguel-cattle-dog', 2, 'Pinscher', NULL, 'https://upload.wikimedia.org/wikipedia/commons/thumb/3/30/Rzesz%C3%B3w_C%C3%A3o_Fila_de_S%C3%A3o_Miguel_1pl.jpg/500px-Rzesz%C3%B3w_C%C3%A3o_Fila_de_S%C3%A3o_Miguel_1pl.jpg', 'Portogallo', 'grande', false, false, 340, 'https://www.fci.be/en/nomenclature/SAINT-MIGUEL-CATTLE-DOG-340.html', 'Wikimedia Commons (CC BY-SA 3.0)', NULL, NULL, NULL, NULL, NULL, NULL, NULL),
  ('Brazilian Terrier', 'BRAZILIAN TERRIER', 'brazilian-terrier', 3, 'Terrier', 'Il Terrier brazileiro, comunemente chiamato Fox Paulistinha, è una razza canina creata in Brasile riconosciuta dalla FCI.', 'https://upload.wikimedia.org/wikipedia/commons/5/54/Brazilian_terrier.JPG', 'Brasile', 'media', false, false, 341, 'https://www.fci.be/en/nomenclature/BRAZILIAN-TERRIER-341.html', 'Wikimedia Commons (CC BY-SA)', NULL, NULL, NULL, NULL, NULL, '{"energy": null, "trainability": null, "shedding": null, "barking": 3, "good_with_children": 5, "good_with_other_dogs": 3}'::jsonb, 'https://it.wikipedia.org/wiki/Terrier_brasileiro'),
