  ('American Akita', 'AMERICAN AKITA', 'american-akita', 5, 'Cani di tipo Spitz e primitivo', NULL, 'https://upload.wikimedia.org/wikipedia/commons/7/78/Akita_Americano_e_Akita_Inu.jpg', 'Giappone', 'media', false, false, 344, 'https://www.fci.be/en/nomenclature/AMERICAN-AKITA-344.html', 'Wikimedia Commons (CC BY-SA 4.0)', 35, 60, 10, 12, false, NULL, NULL),
  ('Jack Russell Terrier', 'JACK RUSSELL TERRIER', 'jack-russell-terrier', 3, 'Terrier', 'Il Jack Russell Terrier è un piccolo terrier da lavoro molto attivo, intelligente, socievole, agile e veloce. Creato dal Reverendo Russell per la caccia alla volpe, determinato con la selvaggina, è oggi anche un buon cane da compagnia.', 'https://upload.wikimedia.org/wikipedia/commons/thumb/5/5d/Smooth_Jack_Russell_Terrier.jpg/330px-Smooth_Jack_Russell_Terrier.jpg', 'Regno Unito', 'media', false, true, 345, 'https://www.fci.be/en/nomenclature/JACK-RUSSELL-TERRIER-345.html', 'Wikimedia Commons (CC BY-SA)', 5, 7, 12, 14, false, NULL, 'https://it.wikipedia.org/wiki/Jack_Russell_terrier'),
  ('Presa Canario', 'PRESA CANARIO', 'presa-canario', 2, 'Pinscher', NULL, 'https://upload.wikimedia.org/wikipedia/commons/thumb/5/56/Presa_Canario_3.jpg/500px-Presa_Canario_3.jpg', 'Spagna', 'grande', false, false, 346, 'https://www.fci.be/en/nomenclature/PRESA-CANARIO-346.html', 'Wikimedia Commons (CC BY-SA 4.0)', 40, 50, 10, 12, false, '{"energy": null, "trainability": null, "shedding": 3, "barking": 3, "good_with_children": 1, "good_with_other_dogs": 1}'::jsonb, NULL),
  ('Pastore Svizzero Bianco', 'WHITE SWISS SHEPHERD DOG', 'pastore-svizzero-bianco', 1, 'Cani da pastore e bovari', NULL, 'https://upload.wikimedia.org/wikipedia/commons/thumb/f/fc/White_Swiss_Shepherd_Dog.jpg/500px-White_Swiss_Shepherd_Dog.jpg', 'Svizzera', 'grande', false, false, 347, 'https://www.fci.be/en/nomenclature/WHITE-SWISS-SHEPHERD-DOG-347.html', 'Wikimedia Commons (CC0)', NULL, NULL, NULL, NULL, NULL, NULL, NULL),
  ('Taiwan Dog', 'TAIWAN DOG', 'taiwan-dog', 5, 'Cani di tipo Spitz e primitivo', 'Il Taiwan Dog è una razza di cane piccolo o medio originario di Taiwan. 
Questi cani sono anche conosciuti come Formosan Mountain Dog, Taiwanese Canis, Taiwanese Native Dog o Takasago Dog. 
Sono cani ben adattati al terreno irregolare e fittamente boscoso di Taiwan, essendo diventati una razza semi-selvatica prima dell''arrivo di diversi regni coloniali e potenze straniere. Nonostante questi adattamenti, i cani Formosani non si sono rinselvatichiti completamente, mantenendo la possibilità di essere addestrati. Infatti, ora sono usati come cani da caccia, cani da guardia, acrobazie, cani da salvataggio o semplicemente come cane da compagnia. I cani di Formosa sono classificati in un tipo medio e due tipi piccoli.', 'https://upload.wikimedia.org/wikipedia/commons/thumb/a/a0/Dog_With_Yellow_Rapeseed_%28242833099%29.jpeg/330px-Dog_With_Yellow_Rapeseed_%28242833099%29.jpeg', 'Taiwan', 'media', false, false, 348, 'https://www.fci.be/en/nomenclature/TAIWAN-DOG-348.html', 'Wikimedia Commons (CC BY-SA)', 10, 15, 12, 15, false, '{"energy": null, "trainability": null, "shedding": 3, "barking": 3, "good_with_children": 3, "good_with_other_dogs": 3}'::jsonb, 'https://it.wikipedia.org/wiki/Taiwan_Dog'),
  ('Romanian Mioritic Shepherd Dog', 'ROMANIAN MIORITIC SHEPHERD DOG', 'romanian-mioritic-shepherd-dog', 1, 'Cani da pastore e bovari', 'Il Romanian Mioritic Shepherd Dog o mioritico o Ciobănesc Românesc Mioritic o Barac è un cane di taglia grande di tipo molossoide che ha avuto origine in Romania nella regione dei monti Carpazi selezionato per la guardia e custodia del bestiame.
Altri nomi con cui è chiamato sono: ciobanesti mioritici, mioritic pastor kutya, chien de berger roumain de mioritza.', 'https://upload.wikimedia.org/wikipedia/commons/thumb/e/e4/Mioritic.jpg/330px-Mioritic.jpg', 'Romania', 'grande', false, false, 349, 'https://www.fci.be/en/nomenclature/ROMANIAN-MIORITIC-SHEPHERD-DOG-349.html', 'Wikimedia Commons (CC BY-SA)', 35, 50, 12, 14, false, '{"energy": null, "trainability": null, "shedding": 3, "barking": 2, "good_with_children": 5, "good_with_other_dogs": 3}'::jsonb, 'https://it.wikipedia.org/wiki/Romanian_Mioritic_Shepherd_Dog'),
  ('Romanian Carpathian Shepherd Dog', 'ROMANIAN CARPATHIAN SHEPHERD DOG', 'romanian-carpathian-shepherd-dog', 1, 'Cani da pastore e bovari', 'Il Romanian Carpathian Shepherd Dog o Carpathian Shepherd Dog o Ciobănesc Românesc Carpatin o Zăvod è un cane da pastore originario della regione dei monti Carpazi in Romania.', 'https://upload.wikimedia.org/wikipedia/commons/thumb/4/41/Carpatin.jpg/330px-Carpatin.jpg', 'Romania', 'grande', false, false, 350, 'https://www.fci.be/en/nomenclature/ROMANIAN-CARPATHIAN-SHEPHERD-DOG-350.html', 'Wikimedia Commons (CC BY-SA)', 45, 65, 12, 14, false, NULL, 'https://it.wikipedia.org/wiki/Romanian_Carpathian_Shepherd_Dog'),
  ('Australian Stumpy Tail Cattle Dog', 'AUSTRALIAN STUMPY TAIL CATTLE DOG', 'australian-stumpy-tail-cattle-dog', 1, 'Cani da pastore e bovari', 'L''Australian Stumpy Tail Cattle Dog è una razza canina originaria dell''Australia riconosciuta in via provvisoria nel 2005.', 'https://upload.wikimedia.org/wikipedia/commons/thumb/1/16/Australian_Stumpy_Tail_Cattle_Dog.jpg/330px-Australian_Stumpy_Tail_Cattle_Dog.jpg', 'Australia', 'grande', false, false, 351, 'https://www.fci.be/en/nomenclature/AUSTRALIAN-STUMPY-TAIL-CATTLE-DOG-351.html', 'Wikimedia Commons (CC BY-SA)', 15, 20, 12, 15, false, '{"energy": null, "trainability": null, "shedding": 2, "barking": 2, "good_with_children": 3, "good_with_other_dogs": 1}'::jsonb, 'https://it.wikipedia.org/wiki/Australian_Stumpy_Tail_Cattle_Dog'),
