  ('Thai Bangkaew Dog', 'THAI BANGKAEW DOG', 'thai-bangkaew-dog', 5, 'Cani di tipo Spitz e primitivo', 'Il Thai Bangkaew Dog o cane Bangkaew (Thai) è una razza di cane asiatico di tipo spitz di taglia media.', 'https://upload.wikimedia.org/wikipedia/commons/thumb/b/be/Thai_Bangkaew_Dog_2.jpg/330px-Thai_Bangkaew_Dog_2.jpg', 'Thailand', 'media', false, false, 358, 'https://www.fci.be/en/nomenclature/THAI-BANGKAEW-DOG-358.html', 'Wikimedia Commons (CC BY-SA)', NULL, NULL, NULL, NULL, NULL, NULL, 'https://it.wikipedia.org/wiki/Thai_Bangkaew_dog'),
  ('Miniature Bull Terrier', 'MINIATURE BULL TERRIER', 'miniature-bull-terrier', 3, 'Terrier', NULL, 'https://upload.wikimedia.org/wikipedia/commons/thumb/8/85/Mini_Bull_Terrier.jpg/500px-Mini_Bull_Terrier.jpg', 'Regno Unito', 'piccola', false, false, 359, 'https://www.fci.be/en/nomenclature/MINIATURE-BULL-TERRIER-359.html', 'Wikimedia Commons (CC BY-SA 3.0)', 8, 14, 12, 15, false, '{"energy": null, "trainability": null, "shedding": 2, "barking": 4, "good_with_children": 3, "good_with_other_dogs": 3}'::jsonb, NULL),
  ('Lancashire Heeler', 'LANCASHIRE HEELER', 'lancashire-heeler', 1, 'Cani da pastore e bovari', 'Il Lancashire Heeler o anche Ormskirk Terrier è una razza di cani originaria dell''Inghilterra di taglia piccola, allevata per la guida e la conduzione del bestiame. 
Il Lancashire Heeler è elencato dal The Kennel Club come razza in via di estinzione. La razza è stata riconosciuta anche dall''American Kennel Club nel 2024.', 'https://upload.wikimedia.org/wikipedia/commons/thumb/2/21/Grupp_1%2C_LANCASHIRE_HEELER%2C_NO_UCH_NO_V-14_NO_V-15_SE_UCH_St%C3%A5hlskyttens_Longed_For_Antony_%2824284065606%29.jpg/330px-Grupp_1%2C_LANCASHIRE_HEELER%2C_NO_UCH_NO_V-14_NO_V-15_SE_UCH_St%C3%A5hlskyttens_Longed_For_Antony_%2824284065606%29.jpg', 'England', 'grande', false, false, 360, 'https://www.fci.be/en/nomenclature/LANCASHIRE-HEELER-360.html', 'Wikimedia Commons (CC BY-SA)', 8, 11, 12, 15, false, '{"energy": null, "trainability": null, "shedding": 3, "barking": 5, "good_with_children": 5, "good_with_other_dogs": 5}'::jsonb, 'https://it.wikipedia.org/wiki/Lancashire_Heeler'),
